/// <summary>
/// Clase para construir LedgerDimensions de tipo contable.
/// </summary>
class IFRDimensionLedgerDimensionBuilderLedger extends IFRDimensionLedgerDimensionBuilderBase
{
    DimensionDefault defaultDimension;

}

Method.Source:
protected void new(LedgerJournalAC _ledgerJournalAC, DimensionDefault _defaultDimension)
{
    ledgerJournalAC = _ledgerJournalAC;
    defaultDimension = _defaultDimension;
}

public static IFRDimensionLedgerDimensionBuilderLedger construct(LedgerJournalAC _ledgerJournalAC, DimensionDefault _defaultDimension)
{
    IFRDimensionLedgerDimensionBuilderLedger IFRDimensionLedgerDimensionBuilderLedger;

    IFRDimensionLedgerDimensionBuilderLedger = new IFRDimensionLedgerDimensionBuilderLedger(_ledgerJournalAC, _defaultDimension);

    return IFRDimensionLedgerDimensionBuilderLedger;
}

public static IFRDimensionLedgerDimensionBuilderLedger constructFromLedgerDimensionDefaultAccount(
    LedgerDimensionDefaultAccount _ledgerDimensionDefaultAccount,
    DimensionDefault _defaultDimension)
{
    IFRDimensionLedgerDimensionBuilderLedger IFRDimensionLedgerDimensionBuilderLedger;

    IFRDimensionLedgerDimensionBuilderLedger = new IFRDimensionLedgerDimensionBuilderLedger(
        LedgerDimensionFacade::getMainAccountIdFromLedgerDimension(_ledgerDimensionDefaultAccount),
        _defaultDimension);

    return IFRDimensionLedgerDimensionBuilderLedger;
}

public static IFRDimensionLedgerDimensionBuilderLedger constructFromLedgerDimension(LedgerDimensionAccount _ledgerDimension)
{
    IFRDimensionLedgerDimensionBuilderLedger IFRDimensionLedgerDimensionBuilderLedger;

    IFRDimensionLedgerDimensionBuilderLedger = new IFRDimensionLedgerDimensionBuilderLedger(
        LedgerDimensionFacade::getMainAccountIdFromLedgerDimension(_ledgerDimension),
        LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(_ledgerDimension));

    return IFRDimensionLedgerDimensionBuilderLedger;
}

/// <summary>
/// Aplica las dimensiones por defecto para una cuenta contable.
/// </summary>
/// <param name = "_mainAccountDefaultDimensionsForAccountThenClassVar">Indica si se fusionan las dimensiones por defecto sobre las de la clase (o al revés).</param>
/// <returns>Devuelve la instancia de la clase.</returns>
public IFRDimensionLedgerDimensionBuilderLedger applyDefaultDimensionsForMainAccount(boolean _mainAccountDefaultDimensionsForAccountThenClassVar = true)
{
    MainAccount mainAccount = MainAccount::findByMainAccountId(ledgerJournalAC);
    MainAccountLegalEntity mainAccountLegalEntity = MainAccountLegalEntity::findByMainAccountLegalEntity(mainAccount.RecId, CompanyInfo::current());

    if (mainAccountLegalEntity.RecId != 0 && mainAccountLegalEntity.DefaultDimension)
    {
        DimensionDefault dimensionMainAccount = mainAccountLegalEntity.DefaultDimension;

        if (_mainAccountDefaultDimensionsForAccountThenClassVar)
        {
            defaultDimension = LedgerDimensionDefaultFacade::serviceMergeDefaultDimensions(dimensionMainAccount, defaultDimension);
        }
        else
        {
            defaultDimension = LedgerDimensionDefaultFacade::serviceMergeDefaultDimensions(defaultDimension, dimensionMainAccount);
        }
    }

    return this;
}

/// <summary>
/// Obtiene el LedgerDimension que hemos construido.
/// </summary>
/// <returns>LedgerDimensionAccount</returns>
public LedgerDimensionAccount getLedgerDimension()
{
    DimensionDynamicAccount dimensionDynamicAccount;
    LedgerDimensionAccount ledgerDimensionAccount;

    dimensionDynamicAccount = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(ledgerJournalAC, LedgerJournalACType::Ledger);
    ledgerDimensionAccount = LedgerDimensionFacade::serviceCreateLedgerDimension(dimensionDynamicAccount, defaultDimension);

    return ledgerDimensionAccount;
}

/// <summary>
/// Convierte un LedgerDimension a una cadena de texto separada por un separador (-).
/// </summary>
/// <returns>Cadena de texto con las dimensiones separadas por guión,</returns>
public str ToString()
{
    return LedgerDimensionFacade::getDisplayValueForLedgerDimension(this.getLedgerDimension());
}

/// <summary>
/// Obtiene el mainAccount.
/// </summary>
/// <returns>Número de la cuenta contable</returns>
public MainAccountNum getMainAccount()
{
    return ledgerJournalAC;
}

/// <summary>
/// Obtiene el DimensionDefault.
/// </summary>
/// <returns>DimensionDefault</returns>
public DimensionDefault getDefaultDimension()
{
    return defaultDimension;
}
